import{_ as t,o as l,c as a,ag as i}from"./chunks/framework.BqfgOMAh.js";const u=JSON.parse('{"title":"在 IDE / Agent 中使用 NexusFlow","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/mcp.md","filePath":"zh/guide/mcp.md"}'),s={name:"zh/guide/mcp.md"};function o(d,e,n,c,r,p){return l(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="在-ide-agent-中使用-nexusflow" tabindex="-1">在 IDE / Agent 中使用 NexusFlow <a class="header-anchor" href="#在-ide-agent-中使用-nexusflow" aria-label="Permalink to &quot;在 IDE / Agent 中使用 NexusFlow&quot;">​</a></h1><p>NexusFlow 0.2.0 在桌面主程序中内置 MCP Server。启用后，Cursor、Claude Code 或其他支持 MCP 的 IDE / Agent 可以连接到 NexusFlow，把 NexusFlow 当作 Unreal Engine 自动化能力入口来使用。</p><p>这不是“把外部 MCP 接入 NexusFlow 主程序”的功能；方向相反：<strong>外部 IDE / Agent 连接 NexusFlow 提供的 MCP Server</strong>，然后通过 NexusFlow 操作 UE 上下文、Blueprint、Widget、模板和节点搜索等能力。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>在 Cursor、Claude Code 或其他 MCP Client 中让 Agent 直接操作 UE 蓝图。</li><li>让外部 IDE 读取当前 UE 编辑器上下文，例如选中资产、打开的蓝图和连接状态。</li><li>使用 NexusFlow Skills 执行受约束的蓝图、Widget、资产等操作。</li><li>在写蓝图逻辑前搜索 UE 节点或复用 Blueprint 模板。</li></ul><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>使用前，请确认：</p><ol><li>已安装并启动 NexusFlow 桌面应用。</li><li>已在 NexusFlow 中启用 MCP 模式。</li><li>MCP Client 已连接到 NexusFlow 提供的 MCP endpoint。</li><li>如需执行 UE 操作，Unreal Engine 已打开，NexusFlow UE 插件已安装并连接。</li></ol><p>如果 MCP Client 无法连接，请先打开 NexusFlow，确认 MCP 模式已启用，并检查 Client 中配置的 endpoint。</p><h2 id="推荐配套安装-nexusflow-skill" tabindex="-1">推荐配套安装 NexusFlow Skill <a class="header-anchor" href="#推荐配套安装-nexusflow-skill" aria-label="Permalink to &quot;推荐配套安装 NexusFlow Skill&quot;">​</a></h2><p>为了让 IDE / Agent 更稳定地使用 NexusFlow MCP，建议安装独立发布的 <a href="https://github.com/maxzhao/nexusflow-skill" target="_blank" rel="noreferrer">NexusFlow Skill</a>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> maxzhao/nexusflow-skill</span></span></code></pre></div><p>它会告诉 Agent 如何检查连接、读取 UE 上下文、搜索并加载 NexusFlow Skills，以及如何安全执行动作。</p><h2 id="推荐工作流" tabindex="-1">推荐工作流 <a class="header-anchor" href="#推荐工作流" aria-label="Permalink to &quot;推荐工作流&quot;">​</a></h2><p>外部 Agent 应使用渐进式披露流程，避免一次性加载过多上下文：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_connection_status</span></span>
<span class="line"><span>  -&gt; get_ue_context</span></span>
<span class="line"><span>  -&gt; search_skills</span></span>
<span class="line"><span>  -&gt; load_skill</span></span>
<span class="line"><span>  -&gt; [load_knowledge]</span></span>
<span class="line"><span>  -&gt; execute_action</span></span></code></pre></div><p>说明：</p><ul><li><code>get_connection_status</code>：任何 UE 操作前先检查连接，只在 <code>connected: true</code> 时继续。</li><li><code>get_ue_context</code>：读取当前 UE 编辑器状态，理解选中资产、打开蓝图和当前上下文。</li><li><code>search_skills</code>：根据用户目标搜索最相关的 NexusFlow Skill。</li><li><code>load_skill</code>：加载 Skill 指南，查看可用函数、参数和约束。</li><li><code>load_knowledge</code>：仅在指南要求或任务需要时加载具体知识主题。</li><li><code>execute_action</code>：按已加载指南构造参数并执行动作。</li></ul><h2 id="可用-mcp-工具" tabindex="-1">可用 MCP 工具 <a class="header-anchor" href="#可用-mcp-工具" aria-label="Permalink to &quot;可用 MCP 工具&quot;">​</a></h2><p>工具名称可能因 MCP Client 配置而带有不同前缀，请以 Client 显示的实时 tool list 和 schema 为准。</p><table tabindex="0"><thead><tr><th>工具</th><th>用途</th></tr></thead><tbody><tr><td><code>get_connection_status</code></td><td>检查 NexusFlow 是否已连接 UE</td></tr><tr><td><code>get_ue_context</code></td><td>获取当前 Unreal Editor 上下文</td></tr><tr><td><code>search_skills</code></td><td>搜索 NexusFlow Skill 模块</td></tr><tr><td><code>load_skill</code></td><td>加载 Skill 指南和可用知识主题</td></tr><tr><td><code>load_knowledge</code></td><td>加载指定 Skill 的专题知识</td></tr><tr><td><code>execute_action</code></td><td>执行 Skill 函数</td></tr><tr><td><code>search_templates</code></td><td>搜索可复用 Blueprint 模板</td></tr><tr><td><code>load_template</code></td><td>加载模板完整定义</td></tr><tr><td><code>search_nodes</code></td><td>搜索 Blueprint 节点和引擎函数</td></tr><tr><td><code>execute_command</code></td><td>执行受支持的编辑器或控制台命令</td></tr><tr><td><code>execute_python_code</code></td><td>最后手段：执行直接 Python，需要明确确认</td></tr></tbody></table><h2 id="安全建议" tabindex="-1">安全建议 <a class="header-anchor" href="#安全建议" aria-label="Permalink to &quot;安全建议&quot;">​</a></h2><ul><li>优先使用 <code>search_skills</code> / <code>load_skill</code> / <code>execute_action</code>，不要直接猜 UE Python API。</li><li>不要重复加载同一个 Skill、知识主题或模板。</li><li>对已有资产做局部、增量修改；完整重写或破坏性操作前必须确认。</li><li>写操作后通过返回结果、读回、编译、保存或截图验证。</li><li><code>execute_python_code</code> 只作为确认后的最后手段。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./agent-skill">NexusFlow Skill</a>：安装独立 Skill，让 IDE / Agent 更稳定地使用 NexusFlow MCP。</li><li><a href="./blueprint-operations">蓝图操作</a>：了解内置蓝图能力。</li><li><a href="./widget-skill">Widget Skill</a>：试用 Widget Blueprint 生成与修改。</li></ul>`,25)])])}const k=t(s,[["render",o]]);export{u as __pageData,k as default};
